UPDATE room_participant SET
	selection_status	= 'SELECTED'
WHERE room_participant_idx		= #{roomParticipantIdx}

UPDATE room_participant SET
	selection_status	= 'NOT_SELECTED'
WHERE room_participant_idx		= #{roomParticipantIdx}

UPDATE room_participant SET
	payment_status		= 'PAID'
WHERE room_participant_idx		= #{roomParticipantIdx}

UPDATE room_participant SET
	left_at		= CURRENT_TIMESTAMP
WHERE room_participant_idx		= #{roomParticipantIdx}
